package arch.day49;

public class Day49Basic {
    public static void main(String[] args) {
        String base = "https://api.example.com";

        // ── Resource URL patterns ──────────────────────────────────────────
        System.out.println("=== REST Resource URL Patterns ===");
        System.out.println("Collection      GET    " + base + "/orders");
        System.out.println("Single item     GET    " + base + "/orders/ord-789");
        System.out.println("Sub-resource    GET    " + base + "/orders/ord-789/items");
        System.out.println("Create          POST   " + base + "/orders");
        System.out.println("Replace full    PUT    " + base + "/orders/ord-789");
        System.out.println("Partial update  PATCH  " + base + "/orders/ord-789");
        System.out.println("Delete          DELETE " + base + "/orders/ord-789");
        System.out.println("Domain action   POST   " + base + "/orders/ord-789/cancel");
        System.out.println();

        // ── HTTP method properties ─────────────────────────────────────────
        // Safe   = does NOT change server state (GET is always safe to call)
        // Idempotent = calling N times == calling 1 time (effect, not response)
        System.out.println("=== HTTP Method Properties ===");
        System.out.println("Method    Safe    Idempotent  Notes");
        System.out.println("GET       Yes     Yes         Cacheable; never change state");
        System.out.println("HEAD      Yes     Yes         Same as GET, no response body");
        System.out.println("OPTIONS   Yes     Yes         CORS preflight / capability probe");
        System.out.println("PUT       No      Yes         Replaces full resource; safe to retry");
        System.out.println("DELETE    No      Yes         Second call may get 404, effect same");
        System.out.println("POST      No      No*         Creates/commands; needs Idempotency-Key");
        System.out.println("PATCH     No      No*         Partial; define merge semantics explicitly");
        System.out.println();
        System.out.println("* POST/PATCH are idempotent ONLY when you add Idempotency-Key design");
        System.out.println();

        // ── Common URL design smells ───────────────────────────────────────
        System.out.println("=== URL Design: Good vs Smell ===");
        System.out.println("GOOD  POST /orders              (noun, collection)");
        System.out.println("SMELL POST /orders/create       (verb in URL = RPC smell)");
        System.out.println("GOOD  POST /orders/ord-789/cancel  (documented domain action)");
        System.out.println("SMELL GET  /cancelOrder?id=789  (GET must never mutate state)");
        System.out.println("GOOD  GET  /users/usr-42/addresses  (sub-resource containment)");
        System.out.println("SMELL GET  /getUserAddresses?userId=42  (query param as path)");
    }
}

package arch.day49;

import java.util.*;

/**
 * Simulates server-side Idempotency-Key deduplication for POST /orders.
 * In production: store is Redis (SETNX + TTL); key scope is (userId, key).
 * Spring equivalent: @PostMapping("/orders") with @RequestHeader("Idempotency-Key")
 */
public class Day49Intermediate {

    static int orderSeq = 1000;

    // idempotencyStore: key -> [statusCode, responseBody, locationHeader]
    static final Map<String, String[]> idempotencyStore = new HashMap<>();

    static String[] createOrder(String idempotencyKey, List<String> items) {
        // ── Step 1: Check dedup store (replays without re-running side effects) ──
        if (idempotencyStore.containsKey(idempotencyKey)) {
            System.out.println("  [DEDUP] Replaying cached response. key=" + idempotencyKey);
            return idempotencyStore.get(idempotencyKey);
        }

        // ── Step 2: Validate payload (Spring: @Valid + BindingResult → 422) ──────
        if (items == null || items.isEmpty()) {
            return new String[]{"422",
                "{\"type\":\"validation-error\",\"detail\":\"items required\"}", null};
        }

        // ── Step 3: Business logic — create the order (DB write, event publish) ──
        String orderId = "ord-" + (++orderSeq);
        String body = "{\"orderId\":\"" + orderId + "\",\"status\":\"PENDING\",\"items\":" + items + "}";
        String location = "Location: /orders/" + orderId;

        // ── Step 4: Cache result for TTL replay (Redis: SETEX key 86400 body) ───
        String[] response = {"201", body, location};
        idempotencyStore.put(idempotencyKey, response);
        System.out.println("  [NEW]   Order created, key cached. orderId=" + orderId);
        return response;
    }

    static void printResponse(String[] r) {
        System.out.println("  Status   : " + r[0]);
        System.out.println("  Body     : " + r[1]);
        if (r[2] != null) System.out.println("  " + r[2]);
    }

    public static void main(String[] args) {
        System.out.println("=== Idempotency-Key Pattern: POST /orders ===");
        System.out.println();

        // ── Scenario A: Normal first call ─────────────────────────────────────────
        System.out.println("Call 1 — first request from client:");
        printResponse(createOrder("req-c8f3a1b2", List.of("PROD-1", "PROD-2")));
        System.out.println();

        // ── Scenario B: Client retries due to network timeout ─────────────────────
        System.out.println("Call 2 — client retries with SAME Idempotency-Key:");
        printResponse(createOrder("req-c8f3a1b2", List.of("PROD-1", "PROD-2")));
        System.out.println();

        // ── Scenario C: Different key = genuinely new operation ──────────────────
        System.out.println("Call 3 — new key = new order:");
        printResponse(createOrder("req-7d2e9c4f", List.of("PROD-5")));
        System.out.println();

        // ── Scenario D: Empty items = validation failure ──────────────────────────
        System.out.println("Call 4 — validation failure (empty items):");
        printResponse(createOrder("req-9a1f0c3e", Collections.emptyList()));
        System.out.println();

        System.out.println("=== Key Design Rules ===");
        System.out.println("Rule 1: Same key + same payload  -> replay cached response (no double charge)");
        System.out.println("Rule 2: Same key + DIFF payload  -> 409 Conflict (key misuse)");
        System.out.println("Rule 3: Key scope               -> per (userId, key) in Redis");
        System.out.println("Rule 4: TTL                     -> 24 hours is a common default");
        System.out.println("Rule 5: Key generation          -> UUID v4 generated by client, not server");
    }
}

package arch.day49;

import java.util.*;

public class Day49Advanced {

    // ── RFC 7807 Problem Details error format ──────────────────────────────
    // Spring 6: ProblemDetail.forStatus(HttpStatus.UNPROCESSABLE_ENTITY)
    record ProblemDetail(String type, String title, int status,
                         String detail, String instance, String traceId) {
        @Override public String toString() {
            String shortType = type.substring(type.lastIndexOf('/') + 1);
            return String.format(
                "{\"type\":\"%s\",\"title\":\"%s\",\"status\":%d,"
                + "\"detail\":\"%s\",\"instance\":\"%s\",\"traceId\":\"%s\"}",
                shortType, title, status, detail, instance, traceId);
        }
    }

    // ── Keyset pagination ──────────────────────────────────────────────────
    // SQL equivalent: WHERE id < :afterId ORDER BY id DESC LIMIT :limit
    // Offset pagination equivalent:  OFFSET page*size  — breaks at high pages
    record OrderPage(List<String> orders, String nextCursor, boolean hasMore) {}

    static OrderPage getOrders(int afterId, int limit) {
        // Simulate DB rows: ids 900 down to 1
        List<String> page = new ArrayList<>();
        for (int id = afterId - 1; id > afterId - 1 - limit && id > 0; id--) {
            page.add("ord-" + id);
        }
        boolean hasMore = page.size() == limit;
        // Cursor is OPAQUE to clients — they must not parse or construct it
        String cursor = hasMore ? "cur_" + page.get(page.size() - 1).replace("ord-", "") : null;
        return new OrderPage(page, cursor, hasMore);
    }

    public static void main(String[] args) {

        // ── 1. Keyset pagination demo ──────────────────────────────────────
        System.out.println("=== Keyset Pagination ===");
        System.out.println("Why keyset? OFFSET 50000 requires DB to skip 50000 rows — slow & unstable");
        System.out.println("Keyset: WHERE id < lastSeenId ORDER BY id DESC — uses index, stable");
        System.out.println();

        OrderPage page1 = getOrders(901, 5);
        System.out.println("Page 1 orders : " + page1.orders());
        System.out.println("nextCursor    : " + page1.nextCursor() + "  <-- opaque, client passes back as-is");
        System.out.println("hasMore       : " + page1.hasMore());
        System.out.println();

        int page2Anchor = Integer.parseInt(page1.nextCursor().replace("cur_", ""));
        OrderPage page2 = getOrders(page2Anchor, 5);
        System.out.println("Page 2 orders : " + page2.orders());
        System.out.println("nextCursor    : " + page2.nextCursor());
        System.out.println("hasMore       : " + page2.hasMore());
        System.out.println();

        // ── 2. RFC 7807 Problem Details examples ──────────────────────────
        System.out.println("=== RFC 7807 Problem Details ===");

        // 422: business rule violation
        System.out.println(new ProblemDetail(
            "https://api.example.com/problems/insufficient-stock",
            "Insufficient Stock", 422,
            "SKU PROD-42: requested 10, available 3",
            "/orders/ord-789", "trace-abc123"));

        // 409: idempotency-key reused with different payload
        System.out.println(new ProblemDetail(
            "https://api.example.com/problems/idempotency-conflict",
            "Idempotency Key Conflict", 409,
            "Key 'req-A1B2' already used with a different request body",
            "/orders", "trace-def456"));

        // 429: rate limited
        System.out.println(new ProblemDetail(
            "https://api.example.com/problems/rate-limited",
            "Too Many Requests", 429,
            "Limit 100 req/min exceeded. Retry-After: 47 seconds",
            "/orders", "trace-ghi789"));
        System.out.println();

        // ── 3. Status code quick reference ────────────────────────────────
        System.out.println("=== Status Code Decision Reference ===");
        System.out.println("201 Created               Resource created — always include Location header");
        System.out.println("204 No Content            Success, no body (DELETE, some PUT)");
        System.out.println("304 Not Modified          ETag matched — client uses its cached copy");
        System.out.println("400 Bad Request           Malformed JSON, wrong types");
        System.out.println("401 Unauthorized          No/invalid auth — add WWW-Authenticate header");
        System.out.println("403 Forbidden             Valid auth, insufficient permission");
        System.out.println("404 Not Found             Resource absent (also used to hide 403)");
        System.out.println("409 Conflict              Duplicate key, illegal state transition");
        System.out.println("412 Precondition Failed   If-Match ETag mismatch (optimistic lock)");
        System.out.println("422 Unprocessable Entity  Valid JSON but business rules violated");
        System.out.println("429 Too Many Requests     Rate limited — add Retry-After header");
        System.out.println("503 Service Unavailable   Overloaded/maintenance — add Retry-After");
    }
}

