package arch.day49;

import java.util.*;

/**
 * Exercise solution: POST /orders with full idempotency, validation,
 * auth check, and RFC 7807 error format.
 *
 * In a real Spring app:
 *   @PostMapping("/orders")
 *   ResponseEntity<Order> create(
 *       @RequestHeader("Idempotency-Key") String key,
 *       @Valid @RequestBody CreateOrderRequest req,
 *       @AuthenticationPrincipal User user)
 */
public class Day49Exercise {

    // Server-side store: idempotencyKey -> [statusCode, body, locationHeader]
    // Production: Redis hash with SETNX + EXPIRE 86400, scoped to (userId, key)
    static final Map<String, String[]> store = new HashMap<>();
    static int seq = 1000;

    static String[] postOrder(String key, String customerId,
                              List<String> items, double total) {
        // ── 1. Dedup check — replay without re-running side effects ──
        if (store.containsKey(key)) {
            System.out.println("  [REPLAY] key=" + key);
            return store.get(key);
        }

        // ── 2. Auth check — 401 if missing, 403 if wrong role ──────────
        if (customerId == null || customerId.isBlank()) {
            return new String[]{"401",
                "{\"type\":\"unauthorized\",\"status\":401,\"detail\":\"Bearer token required\"}",
                null};
        }

        // ── 3. Validate payload — 422 for business rule violations ─────
        if (items == null || items.isEmpty()) {
            return new String[]{"422",
                problem("validation-error", "Order must contain at least one item", "/orders"),
                null};
        }
        if (total <= 0) {
            return new String[]{"422",
                problem("validation-error", "Total must be positive, got: " + total, "/orders"),
                null};
        }
        if (items.size() > 10) {
            return new String[]{"422",
                problem("max-items-exceeded",
                    "Max 10 items per order; received " + items.size(), "/orders"),
                null};
        }

        // ── 4. Create order (DB insert + event publish) ─────────────────
        String orderId = "ord-" + (++seq);
        String body = String.format(
            "{\"orderId\":\"%s\",\"status\":\"PENDING\",\"total\":%.2f}",
            orderId, total);
        String location = "/orders/" + orderId;

        // ── 5. Cache response for TTL replay ────────────────────────────
        // Trade-off: longer TTL = larger Redis footprint but safer retry window
        String[] resp = {"201", body, location};
        store.put(key, resp);
        System.out.println("  [NEW] orderId=" + orderId);
        return resp;
    }

    static String problem(String type, String detail, String instance) {
        // RFC 7807 — Spring 6: ProblemDetail.forStatusAndDetail(status, detail)
        return String.format(
            "{\"type\":\"https://api.example.com/problems/%s\","
            + "\"status\":422,\"detail\":\"%s\",\"instance\":\"%s\"}",
            type, detail, instance);
    }

    static void call(String label, String key, String cust,
                     List<String> items, double total) {
        System.out.println("--- " + label + " ---");
        String[] r = postOrder(key, cust, items, total);
        System.out.println("  HTTP " + r[0]);
        System.out.println("  Body     : " + r[1]);
        if (r[2] != null) System.out.println("  Location : " + r[2]);
        System.out.println();
    }

    public static void main(String[] args) {
        System.out.println("=== POST /orders — Exercise Solution ===\n");

        call("Case 1: Valid new order",
            "idem-key-abc", "cust-42", List.of("PROD-1", "PROD-2"), 99.99);

        call("Case 2: Same key retry (network timeout simulation)",
            "idem-key-abc", "cust-42", List.of("PROD-1", "PROD-2"), 99.99);

        call("Case 3: Validation failure — empty items",
            "idem-key-def", "cust-42", Collections.emptyList(), 0.0);

        call("Case 4: Unauthenticated — no customer",
            "idem-key-ghi", null, List.of("PROD-1"), 49.99);

        call("Case 5: Too many items",
            "idem-key-jkl", "cust-99",
            List.of("P1","P2","P3","P4","P5","P6","P7","P8","P9","P10","P11"), 299.0);

        System.out.println("=== Status Code Summary ===");
        System.out.println("201 + Location  -> order created successfully");
        System.out.println("422             -> business rule violated (RFC 7807 body)");
        System.out.println("401             -> caller not authenticated");
        System.out.println("409             -> same key + different payload (conflict)");
        System.out.println("REPLAY 201      -> duplicate key, replayed from store");
    }
}

